+export function scrub(text, redactions = []) {
+  let out = text;
+  for (const { name, form } of redactions) out = out.split(form).join(`[REDACTED:env:${name}]`);
+  for (const [kind, re] of SECRET_PATTERNS) out = out.replace(re, `[REDACTED:${kind}]`);
