+  ['slack-token', /\bxox[baprs]-[A-Za-z0-9-]{10,}\b/g],
+  ['jwt', /\beyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{5,}\b/g],
